function xgbPredict(m, x) {
  let s = m.bs;
  for (const t of m.t) {
    let i = 0;
    while (true) {
      const n = t[i];
      if (n[0] === -1) {
        s += n[3];
        break;
      }
      if (x[n[0]] < n[1])
        i++;
      else
        i = n[2];
    }
  }
  return s;
}
